'use client';

import { useEffect } from 'react';
import { useSiteSettings } from '@/hooks/useSiteSettings';

export function FaviconManager() {
  const { settings, isLoading } = useSiteSettings();

  useEffect(() => {
    if (isLoading) return;

    // Update favicon
    if (settings.favicon.url) {
      let favicon = document.querySelector('link[rel="icon"]') as HTMLLinkElement;
      if (favicon) {
        favicon.href = settings.favicon.url;
      } else {
        favicon = document.createElement('link');
        favicon.rel = 'icon';
        favicon.href = settings.favicon.url;
        document.head.appendChild(favicon);
      }
    }

    // Update apple touch icon
    if (settings.favicon.appleTouchIcon) {
      let appleTouchIcon = document.querySelector('link[rel="apple-touch-icon"]') as HTMLLinkElement;
      if (appleTouchIcon) {
        appleTouchIcon.href = settings.favicon.appleTouchIcon;
      } else {
        appleTouchIcon = document.createElement('link');
        appleTouchIcon.rel = 'apple-touch-icon';
        appleTouchIcon.href = settings.favicon.appleTouchIcon;
        document.head.appendChild(appleTouchIcon);
      }
    }

    // Update web manifest
    if (settings.favicon.manifest) {
      let manifest = document.querySelector('link[rel="manifest"]') as HTMLLinkElement;
      if (manifest) {
        manifest.href = settings.favicon.manifest;
      } else {
        manifest = document.createElement('link');
        manifest.rel = 'manifest';
        manifest.href = settings.favicon.manifest;
        document.head.appendChild(manifest);
      }
    }
  }, [settings.favicon, isLoading]);

  // This component doesn't render anything
  return null;
}